-- ═══════════════════════════════════════════════════
-- 2. INSERT program_modes (базовые: free_chat + author_chat)
-- ═══════════════════════════════════════════════════

INSERT INTO program_modes (program_id, mode_template_id, enabled, sort_order, access_type, config)
SELECT
  p.id,
  mt.id,
  CASE
    WHEN mt.key IN ('free_chat', 'author_chat') THEN true
    ELSE false
  END,
  mt.default_sort_order,
  CASE
    WHEN mt.key = 'free_chat' THEN 'free'
    ELSE 'paid'
  END,
  '{}'::jsonb
FROM programs p
CROSS JOIN mode_templates mt
WHERE p.slug = 'razgovorny-gipnoz'
  AND mt.key IN ('free_chat', 'author_chat');

